def _unpack_packbits(source: bytes, expected: int) -> bytes:
    output = bytearray()
    index = 0
    while index < len(source) and len(output) < expected:
        header = source[index]
        index += 1
        if header < 128:
            run = header + 1
            output.extend(source[index : index + run])
            index += run
        elif header > 128:
            run = 257 - header
            if index >= len(source):
                break
            output.extend(bytes([source[index]]) * run)
            index += 1
        else:
            break
    if len(output) < expected:
        output.extend(b"\x00" * (expected - len(output)))
    return bytes(output[:expected])

