def _read_strip_bytes(
    data: bytes,
    offsets: list[int],
    byte_counts: list[int],
    compression: int,
    expected: int,
) -> bytes:
    chunks = bytearray()
    for offset, count in zip(offsets, byte_counts):
        if offset + count > len(data):
            raise TiffDecodeError("TIFF strip data is truncated.")
        chunk = data[offset : offset + count]
        if compression == _COMPRESSION_NONE:
            chunks.extend(chunk)
        elif compression == _COMPRESSION_PACKBITS:
            remaining = expected - len(chunks)
            chunks.extend(_unpack_packbits(chunk, remaining))
        else:
            raise TiffDecodeError(f"Unsupported TIFF compression {compression}.")
    if len(chunks) < expected:
        raise TiffDecodeError("TIFF strip data is shorter than expected.")
    return bytes(chunks[:expected])

