def _decode_rgb_chunky(
    strip_data: bytes,
    width: int,
    height: int,
    samples_per_pixel: int,
) -> Raster:
    expected = width * height * samples_per_pixel
    if len(strip_data) < expected:
        raise TiffDecodeError("TIFF RGB data is incomplete.")
    if samples_per_pixel == 1:
        pixels = bytearray(width * height * 3)
        for index, value in enumerate(strip_data[: width * height]):
            offset = index * 3
            pixels[offset : offset + 3] = bytes((value, value, value))
        return Raster(width, height, 3, pixels)
    if samples_per_pixel == 3:
        return Raster(width, height, 3, bytearray(strip_data[:expected]))
    if samples_per_pixel == 4:
        rgba = strip_data[: width * height * 4]
        pixels = bytearray(width * height * 3)
        for index in range(width * height):
            source = index * 4
            target = index * 3
            pixels[target : target + 3] = rgba[source : source + 3]
        return Raster(width, height, 3, pixels)
    raise TiffDecodeError(f"Unsupported TIFF samples per pixel: {samples_per_pixel}.")

