def decode_tiff(data: bytes) -> Raster:
    if len(data) < 8:
        raise TiffDecodeError("TIFF data is too short.")
    endian = data[0:2]
    if endian == b"II":
        little_endian = True
    elif endian == b"MM":
        little_endian = False
    else:
        raise TiffDecodeError("Not a TIFF image.")

    if _read_u16(data, 2, little_endian) != 42:
        raise TiffDecodeError("Invalid TIFF magic number.")

    ifd_offset = _read_u32(data, 4, little_endian)
    tags, _next_ifd = _parse_ifd(data, ifd_offset, little_endian)
    return _decode_ifd_image(data, tags, little_endian)
